import{_ as i,o as n,c as r,ag as l}from"./chunks/framework.DXGyWiRo.js";const t="/images/uebung078.jpg",s="/images/uebung079.jpg",h=JSON.parse('{"title":"Übung Lektion 49","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung49.md","filePath":"lektionen/uebung49.md"}'),a={name:"lektionen/uebung49.md"};function o(m,e,g,u,p,d){return n(),r("div",null,[...e[0]||(e[0]=[l('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-49" tabindex="-1">Übung Lektion 49 <a class="header-anchor" href="#ubung-lektion-49" aria-label="Permalink to &quot;Übung Lektion 49&quot;">​</a></h1><p>Bestimmen Sie folgende Formen:</p><ol><li>गृहाणि । गृह n. Nom.Akk.pl.n.</li><li>नमानि । नम् 1P Imp.1.sg.P</li><li>नामानि । नामन् n. Nom.Akk.pl.n.</li><li>नामनि । नामन् n. Lok.sg.n. (neben नाम्नि)</li><li>मत्यै । मति f. Dat.sg.f.</li><li>मन्यै । मन् 4Ā Imp.1.sg.Ā.Pass.</li><li>मान्यै । मन् 4Ā Kaus.Pass.Imp.1.sg.</li><li>मान्यैः । मन् 4Ā Kaus.Gerundiv.Instr.pl.m.n.</li><li>अहम् । ich N.sg.</li><li>अहन् । हन् 2P Impf.2.3.sg.P.</li><li>आत्थ । अह् Perf.2.sg.P</li><li>आत्त । अद् 2P Impf.2.pl.P</li><li>आध्वम् । आस् 2Ā Impf.2.pl.Ā ; Imper.2.pl.Ā</li><li>अत्थ । अद् 2P Ind.Präs.2.pl.P</li><li>ते । त्वम् enklit.Dat.Gen. ; तद् 3 Nom.pl.m.</li><li>स्थ । अस् 2P Ind.Präs.2.pl.P</li><li>तस्थ । स्था 1P Perf. IV.2.pl.P</li><li>तस्य । तद् 3 Gen.sg.m.n.</li><li>दाता । दातृ Nom.sg.m.</li><li>तता । तन् 8U PPP.Nom.sg.f.</li><li>तथा । &quot;so&quot;</li><li>तदा । &quot;dann, damals&quot;</li><li>तुद । तुद् 6U Imper.2.sg.P</li><li>शेकिथ । शक् 5P Perf. Vb.2.sg.P (neben शशक्थ)</li><li>अनृतम् । अनृत n. Nom.Akk.sg.n.</li><li>अदूष्यः । दुष् 4P Kaus.Gerundiv.Nom.sg.m. + अ-</li><li>अदुष्यः । दुष् 4P Impf.2.sg.P</li><li>त्वत् । त्वम् Abl.sg.</li><li>यदि । &quot;wenn&quot;</li><li>यति । इ 2P Part.Präs.P.Lok.sg.m.n.Vok.sg.f.</li><li>याति । या 2P Ind.Präs.2.sg.P ; Part.Präs.P.Lok.sg.m.n.Vok.sg.f.</li><li>यातुः । यातृ Abl.Gen.sg.m.</li><li>यतः । &quot;von wo&quot; ;  इ Part.Präs.P.Gen.Abl.sg.m.n. ; यम् 1P PPP.Nom.sg.m.</li><li>यातः । यातृ Vok.sg.m. ; या Part.Präs.P.Gen.Abl.sg.m.n. ; PPP.Nom.sg.m.</li><li>आसीथाः । आस् 2Ā Opt.2.sg.Ā</li><li>वक्थ । वच् 2P Ind.Präs.2.pl.P</li><li>बन्धनीय । बन्ध् 9P Gerundiv.Vok.sg.m.n.</li><li>गायी । गायिन् 3 Nom.sg.m.</li><li>मय्हम् । अहम् Dat.sg.</li></ol><p><img src="'+t+'" alt=""><br> Abb.: गायी<br> Baul = বাউল<br> Puducherry = புதுச்சேரி<br> [Bildquelle: Meditant. -- <a href="http://www.flickr.com/photos/meditant/433770994/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/meditant/433770994/</a>. -- Zugriff am 2009-01-23. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>बान (7. Jhdt. n. Chr.): कादम्बरी, ed. M. R. Kale, 1968, S. 35f.</p><p>Fragen des Königs शूद्रक von विदिशा an den Papagei वैशम्पायन:</p><p>नरपतिरब्रवीत् । आस्तां तावत्सर्वमेवेदम् । अपनयतु नः कुतूहलम् । आवेदयतु भवानादितः प्रभृति कार्त्न्येनात्मनो जन्म कस्मिन्देशे । भवान्कथं जातः । केन वा नाम कृतम् । का माता । कस्ते पिता । कथं वेदानामागमः । कथं शास्त्राणां परिचयः । कुतः कलाः समासादिताः । किं जन्मान्तरानुस्मरणमुत वरप्रदानम् । अथवा विहंगवेषधारी कश्चिच्छन्नं विवससि । क्व वा पूर्वमुषितम् । कियद्वा वयः । कथं पञ्जरबन्धः । कथं चाण्डालहस्तगमनम् । इह वा कथमागमनमिति ।</p><p>वैशम्पायनस्तु स्वयमुपजातकुतूहलेन सबहुमानमवनि्पतिना पृष्टो मुहूर्तमिव ध्यात्वा सादरमब्रवीत् । देव मतीयं कथा । यदि कौतुकमाकर्ण्यताम् ॥</p><blockquote><p>Der König sprach: &quot;Lassen wir all das auf sich beruhen! Befriedigen Sie unsere Neugier! Herr!, erzählen Sie uns von Anfang an: In welchem Land wurden Sie geboren? Wer hat Ihnen den Namen gegeben? Wer ist Ihre Mutter. Wie haben Sie die Veden erhalten? Wie haben Sie sich mit den Lehrwerken vertraut gemacht? Woher haben Sie die Künste erworben? Können Sie sich an frühere Geburten erinnern oder Wünsche erfüllen? Oder bewohnen Sie indem Sie das Kleid eines Vogels tragen ein Versteck? Oder wo wohnten Sie früher? Oder wie alt sind Sie? Wie wurden Sie in einen Käfig gefangen? Und wie sind Sie in die Hände von Cāṇḍālas gekommen? Oder wie sind Sie hierher gekommen?&quot;</p><p>Vaiśampanya aber, der vom Herrn der Erde mit spontan entstandener Neugier mit großem Respekt gefragt worden war, überlegte einen Augenblick und antwortete dann voll Hochachtung: &quot;König, das ist eine lange Geschichte. Wenn es Sie interessiert, leihen Sie  mir Ihr Ohr!&quot;</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: शुकः<br> Kranker Papagei, Jain Bird Hospital, Old Delhi<br> [Bildquelle: arimoore. -- <a href="http://www.flickr.com/photos/arimoore/316483575/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/arimoore/316483575/</a>. -- Zugriff am 2009-01-23. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielel Nutzung)]</p>',11)])])}const c=i(a,[["render",o]]);export{h as __pageData,c as default};
